package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.asn.AsnTransportPerformanceApplicationService;import jakarta.servlet.http.*;import jakarta.validation.constraints.*;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.security.oauth2.jwt.Jwt;import org.springframework.web.bind.annotation.*;import java.time.YearMonth;import java.util.*;
@RestController @RequestMapping("/api/supplier/v1/suppliers/{supplierId}/transport-performance")public class AsnTransportPerformanceController {private final AsnTransportPerformanceApplicationService service;public AsnTransportPerformanceController(AsnTransportPerformanceApplicationService service){this.service=service;}@GetMapping public ApiResponse<List<AsnTransportPerformanceApplicationService.View>> arrived(@PathVariable long supplierId,@RequestParam @Pattern(regexp="\\d{4}-\\d{2}")String period,@AuthenticationPrincipal Jwt jwt,HttpServletRequest r){return ApiResponse.success(service.arrived(supplierId,YearMonth.parse(period),scope(jwt)),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}private Long scope(Jwt jwt){Number n=jwt.hasClaim("supplier_id")?jwt.getClaim("supplier_id"):null;return n==null?null:n.longValue();}}
